@prefix owl: <http://www.w3.org/2002/07/owl#>.
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>.
@prefix xsd: <http://www.w3.org/2001/XMLSchema#>.
@prefix ADIRO: <https://burohappoldmachinelearning.github.io/ADIRO/>.
@prefix aec: <https://burohappoldmachinelearning.github.io/ADIRO/aec_drawing_metadata/>.
@prefix ae: <https://burohappoldmachinelearning.github.io/ADIRO/aec_drawing_metadata#>.

ADIRO:aec_drawing_metadata
    a owl:Ontology;
    rdfs:comment "Sheet/layout/document structure for AEC drawings.";
    rdfs:label "AEC Drawing Metadata Ontology";
    owl:imports owl:;
    owl:versionInfo "1.0.0";
    owl:versionIRI aec:1.0.0 .
ae:Base
    a owl:Class;
    rdfs:label "Base";
    rdfs:subClassOf ae:DetailLocation;
    ae:labellableRoot false.
ae:contains
    a owl:ObjectProperty;
    rdfs:comment
        "Direct containment: indicates physical containment of something within a parent thing (e.g. object in a box). Min cardinality 0 by default (can contain).";
    rdfs:domain owl:Thing;
    rdfs:label "contains";
    rdfs:range owl:Thing.
ae:Corner
    a owl:Class;
    rdfs:label "Corner";
    rdfs:subClassOf ae:DetailLocation;
    ae:labellableRoot false.
ae:Detail
    a owl:Class;
    rdfs:comment "Detail drawing";
    rdfs:label "Detail";
    rdfs:subClassOf
        ae:DrawingType,
            [
                a owl:Restriction;
                owl:maxQualifiedCardinality "1"^^xsd:nonNegativeInteger;
                owl:minQualifiedCardinality "0"^^xsd:nonNegativeInteger;
                owl:onClass ae:DetailLocation;
                owl:onProperty ae:has
            ],
            [
                a owl:Restriction;
                owl:onClass ae:Orientation;
                owl:onProperty ae:has;
                owl:qualifiedCardinality "1"^^xsd:nonNegativeInteger
            ];
    ae:labellableRoot true.
ae:DetailLocation
a owl:Class; rdfs:label "Detail location"; ae:labellableRoot false.
ae:DrawingElement
    a owl:Class;
    rdfs:comment
        "Element depicted on a drawing. Contained by Layout. Can be a Facade system or Facade component, or other domain-specific symbols, or generic symbols like dimensions, grids, etc.";
    rdfs:label "Drawing element";
    ae:labellableRoot false.
ae:DrawingOrientation
    a owl:Class;
    rdfs:label "DrawingOrientation";
    rdfs:subClassOf ae:Landscape, ae:Portrait.
ae:DrawingSheet
    a owl:Class;
    rdfs:comment "Top-level container for a drawing. Contains Layout(s).";
    rdfs:label "Drawing Sheet";
    rdfs:subClassOf
            [
                a owl:Restriction;
                owl:maxQualifiedCardinality "1"^^xsd:nonNegativeInteger;
                owl:minQualifiedCardinality "0"^^xsd:nonNegativeInteger;
                owl:onClass ae:RevisionTable;
                owl:onProperty ae:contains;
                owl:qualifiedCardinality "1"^^xsd:nonNegativeInteger
            ],
            [
                a owl:Restriction;
                owl:minQualifiedCardinality "0"^^xsd:nonNegativeInteger;
                owl:onClass ae:Note;
                owl:onProperty ae:contains
            ],
            [
                a owl:Restriction;
                owl:minQualifiedCardinality "1"^^xsd:nonNegativeInteger;
                owl:onClass ae:Layout;
                owl:onProperty ae:contains
            ],
            [
                a owl:Restriction;
                owl:onClass ae:DrawingOrientation;
                owl:onProperty ae:has;
                owl:qualifiedCardinality "1"^^xsd:nonNegativeInteger
            ];
    ae:labellableRoot false.
ae:DrawingType
    a owl:Class;
    rdfs:comment "Type of drawing view";
    rdfs:label "Drawing type";
    ae:labellableRoot false.
ae:Elevation
    a owl:Class;
    rdfs:label "Elevation";
    rdfs:subClassOf ae:DrawingType;
    ae:labellableRoot true.
ae:exampleImage
    a owl:AnnotationProperty;
    rdfs:comment
    "Links a class or concept to an example image illustrating it."@en;
    rdfs:label "example image"@en.
ae:hasProperty
    a owl:ObjectProperty;
    rdfs:comment
        "Subject is characterised by a property, or quality. Used for example to indicate qualitative things like 'it is vertical' or 'it has a colour blue'.";
    rdfs:domain owl:Thing;
    rdfs:label "hasProperty";
    rdfs:range owl:Thing.
ae:Head
    a owl:Class;
    rdfs:label "Head";
    rdfs:subClassOf ae:DetailLocation;
    ae:labellableRoot false.
ae:Horizontal
    a owl:Class;
    rdfs:label "Horizontal";
    rdfs:subClassOf ae:Orientation;
    ae:labellableRoot true.
ae:Image
    a owl:Class;
    rdfs:label "Image";
    rdfs:subClassOf ae:Note;
    ae:labellableRoot true.
ae:labellableRoot
    a owl:AnnotationProperty;
    rdfs:comment
        "When true, this class can be used as a label by annotators (solid contour in diagram). When false, non-labellable (dashed contour).";
    rdfs:label "Labellable root";
    rdfs:range xsd:boolean.
ae:Landscape a owl:Class; rdfs:label "Landscape"; ae:labellableRoot true.

ae:Layout
    a owl:Class;
    rdfs:comment
        "Drawing layout - contained by DrawingSheet. Contains DrawingElement(s), annotations, drawing type, and content.";
    rdfs:label "Layout";
    rdfs:subClassOf
            [
                a owl:Restriction;
                owl:minQualifiedCardinality "0"^^xsd:nonNegativeInteger;
                owl:onClass ae:DrawingElement;
                owl:onProperty ae:contains
            ],
            [
                a owl:Restriction;
                owl:onClass ae:DrawingType;
                owl:onProperty ae:has;
                owl:qualifiedCardinality "1"^^xsd:nonNegativeInteger
            ];
    ae:labellableRoot true.
ae:Legend
    a owl:Class;
    rdfs:comment
        "A legend containing mapping information between symbols and a text signifier.";
    rdfs:label "Legend";
    rdfs:subClassOf ae:Metadata;
    ae:labellableRoot true.
ae:Metadata
    a owl:Class;
    rdfs:comment "Can be standalone label - drawing metadata";
    rdfs:label "Metadata";
    ae:labellableRoot false.
ae:Note
    a owl:Class;
    rdfs:label "Note";
    rdfs:subClassOf ae:Metadata;
    ae:labellableRoot true.
ae:Orientation
    a owl:Class;
    rdfs:comment "Can be standalone label - drawing orientation";
    rdfs:label "Detail Orientation";
    ae:labellableRoot false.
ae:Perspective
    a owl:Class;
    rdfs:label "Perspective";
    rdfs:subClassOf ae:DrawingType;
    ae:labellableRoot true.
ae:Plan
    a owl:Class;
    rdfs:label "Plan";
    rdfs:subClassOf ae:DrawingType;
    ae:labellableRoot true.
ae:Portrait a owl:Class; rdfs:label "Portrait"; ae:labellableRoot true.

ae:refersToDrawingId
    a owl:DatatypeProperty;
    rdfs:comment
        "References another Drawing by using a drawing identifier, like a drawing number.";
    rdfs:domain ae:TextualNote;
    rdfs:label "refersToDrawingId";
    rdfs:range xsd:string.
ae:RevisionTable
    a owl:Class;
    rdfs:label "Revision table";
    rdfs:subClassOf ae:Metadata;
    ae:labellableRoot true.
ae:Section
    a owl:Class;
    rdfs:label "Vertical Section";
    rdfs:subClassOf ae:DrawingType;
    ae:labellableRoot true.
ae:SlabEdge
    a owl:Class;
    rdfs:label "Slab edge";
    rdfs:subClassOf ae:DetailLocation;
    ae:labellableRoot false.
ae:TextualNote
a owl:Class; rdfs:label "Text"; rdfs:subClassOf ae:Note; ae:labellableRoot true.
ae:Titleblock
    a owl:Class;
    rdfs:label "Titleblock";
    rdfs:subClassOf ae:Metadata;
    ae:labellableRoot true.
ae:Typical
    a owl:Class;
    rdfs:label "Typical";
    rdfs:subClassOf ae:DetailLocation;
    ae:labellableRoot false.
ae:Vertical
    a owl:Class;
    rdfs:label "Vertical";
    rdfs:subClassOf ae:Orientation;
    ae:labellableRoot true.

